INSERT INTO products (id, sku, title_it, title_en, category_id, price, stock_quantity, box_quantity, description_it, description_en, image_urls, is_accessory, attributes, created_at, is_active, price_tiers) VALUES ('70d542e5-b9c6-4398-a3a8-cd56ed3e8b9c', 'DPE05.0020', 'Plaisir', NULL, NULL, 1.96, 0, 0, '<p>Il dispenser Plaisir, dal design ergonomico e moderno, &egrave; stato progettato per garantire il massimo comfort nell&rsquo;erogazione del prodotto. Ideale per &nbsp;un&rsquo;ampia gamma di prodotti cosmetici, per la detergenza e per la cura dei capelli.</p>  <p>Dosaggio 200 mcl</p>', '<p>The dispenser pump Plaisir, with ergonomic and modern form, has been designed to guarantee the best dispensing performances. It is ideal solution for a variety of skincare, personal care and haircare products.</p>  <p>Dosage 200 mcl</p>', '["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/DPE05.0020.jpg"]', TRUE, '{"ml": 0, "colore": "RINFORZATA ARGENTO SATINATO PER FLAC SQUARE 30 ML", "finitura": "Nessuna finitura", "categoria": "Dispenser", "materiale": "PP", "imboccatura": "EUROPA 5"}', '2026-06-16T09:26:01.428105+00:00', TRUE, '[]');
INSERT INTO products (id, sku, title_it, title_en, category_id, price, stock_quantity, box_quantity, description_it, description_en, image_urls, is_accessory, attributes, created_at, is_active, price_tiers) VALUES ('2aa09d24-d709-42df-a09b-3e14803871de', 'SC125.0215', 'Cristal', NULL, NULL, 0.82, 0, 100, '<p>Il flacone Cristal 125 ml in PETG lucido&nbsp;presenta&nbsp;un design lineare e deciso, estremamente moderno,&nbsp;adatto a collezioni cosmetiche sia femminili che maschili.</p>  <p>note: Bocca Riduttore.</p>', '<p>Cristal 125&nbsp;ml&nbsp;PETG bottle&nbsp;has&nbsp;a glossy&nbsp;cristal clear finishing, a&nbsp;linear and decise design, and an extremely modern appeal. It is&nbsp;the ideal solution for both female and male cosmetic lines.</p>  <p>note: Neck for reducer plug</p>', '["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/SC125.0215.jpg"]', FALSE, '{"ml": 125, "colore": "Neutro satinato", "finitura": "Semitrasparente", "categoria": "Flaconi plastica", "materiale": "PETG", "imboccatura": "GCMI 24/410"}', '2026-06-16T09:25:04.809095+00:00', TRUE, '[]');
