INSERT INTO products (id, sku, title_it, title_en, category_id, price, stock_quantity, box_quantity, description_it, description_en, image_urls, is_accessory, attributes, created_at, is_active, price_tiers) VALUES ('8325489d-318a-4c54-a4bd-9781014a1cf2', 'CZ410.0027', 'Twist-Off Sirio', NULL, NULL, 0.78, 5740, 1500, '<p>La capsula Sirio &egrave; caratterizzata dalla chiusura&nbsp;twist-off che rende&nbsp;l&#39;erogazione estremamente pratica e funzionale. Basta ruotare la capsula di mezzo giro e il fluido potr&agrave; fuoriuscire dal flacone attraverso il foro. Ruotarla nel senso inverso per chiudere nuovamente la capsula.</p>  <p><strong>COMPATIBILE SOLO CON FLACONI IN PLASTICA&nbsp;AMBRA 125 ML E AMBRA 250 ML CON LA STESSA BOCCA</strong></p>  <p>GUARNIZIONE INCLUSA</p>', '<p>The cap Sirio is characterized by the twist-off closure system that&nbsp;makes&nbsp;the dispensing extremely practical and easy to use. Just rotate the cap of half of a turn to make the lotion&nbsp;come out from the bottle. Then turn back the cap to close it again.</p>  <p><strong>FIT ONLY WITH PLASTIC BOTTLES AMBRA 125 ML AND 250 ML WITH SAME NECK FINISH.</strong></p>  <p>LINER INCLUDED</p>', '["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/CZ410.0027.jpg"]', TRUE, '{"ml": 0, "colore": "Bianco opaco", "finitura": "Nessuna finitura", "categoria": "Capsule - Disctop", "materiale": "PP", "imboccatura": "TWIST-OFF"}', '2026-06-16T09:26:14.136443+00:00', TRUE, '[]');
INSERT INTO products (id, sku, title_it, title_en, category_id, price, stock_quantity, box_quantity, description_it, description_en, image_urls, is_accessory, attributes, created_at, is_active, price_tiers) VALUES ('d5833d7f-e7fc-47d4-9ac2-f1e7332bfee4', 'SC125.0231', 'Ambra', NULL, NULL, 0.42, 0, 100, '<p>Il flacone&nbsp;in plastica Ambra 125&nbsp;ml presenta&nbsp;un fascino senza tempo. Il design armonioso ed equilibrato lo&nbsp;rende ideale per prodotti cosmetici viso, corpo, capelli e&nbsp;detergenza.</p>', '<p>Ambra 125 ml plastic bottle&nbsp;has&nbsp;a timeless charme. The harmonious and well-balanced design makes it&nbsp;the ideal packaging solutions for cosmetic, personal care and&nbsp;haircare&nbsp;products.</p>', '["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/SC125.0231.jpg"]', FALSE, '{"ml": 125, "colore": "Bianco", "finitura": "Nessuna finitura", "categoria": "Flaconi plastica", "materiale": "PEHD", "imboccatura": "GCMI 24/410"}', '2026-06-16T09:24:53.549583+00:00', TRUE, '[]');
INSERT INTO products (id, sku, title_it, title_en, category_id, price, stock_quantity, box_quantity, description_it, description_en, image_urls, is_accessory, attributes, created_at, is_active, price_tiers) VALUES ('935223fd-17c8-45cf-b0ba-b9b137d3537c', 'DI400.0055', 'York', NULL, NULL, 0.42, 17730, 0, '<p>Il dispenser York, grazie al suo speciale meccanismo &quot;pump up&quot;, rappresenta la perfetta soluzione per l&#39;erogazione di prodotti struccanti e&nbsp;nail care. Le&nbsp;due&nbsp;molle assicurano&nbsp;un&#39;erogazione uniforme ed il cover flip top garantisce una conservazione igienica del prodotto.</p>  <p>Dosaggio pompa: 500 mcl.</p>', '<p>The York dspenser pump, thanks to its special &quot;pump up&quot; mechanism, represents the perfect solution for cleaner waters and nail care products. The double spring provide&nbsp;a confortable use and the flip top cover guarantee an hygienic conservation of the product.</p>  <p>Dosage: 500 mcl.</p>', '["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/DI400.0055.jpg"]', TRUE, '{"ml": 0, "colore": "BIANCO + NEUTRO", "finitura": "Nessuna finitura", "categoria": "Dispenser", "materiale": "PP+PE", "imboccatura": "Push Pump"}', '2026-06-16T09:26:18.636973+00:00', TRUE, '[]');
INSERT INTO products (id, sku, title_it, title_en, category_id, price, stock_quantity, box_quantity, description_it, description_en, image_urls, is_accessory, attributes, created_at, is_active, price_tiers) VALUES ('73cb781b-f076-4c9c-802f-25661fdd5c42', 'SC200.0264', 'Venus', NULL, NULL, 0.55, 0, 100, '<p>I flaconi in plastica Venus sono caratterizzati da un desing pulito e slanciato, ideale per prodotti cosmetici viso, corpo, capelli, detergenza.</p>', '<p> Venus plastic bottles are characterized by a clean and slender design, ideal for face, body, hair and cleansing cosmetic products.</p>', '["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/SC200.0264.jpg"]', FALSE, '{"ml": 200, "colore": "Bianco", "finitura": "Perlato", "categoria": "Flaconi plastica", "materiale": "PP", "imboccatura": "GCMI 28/400"}', '2026-06-16T09:26:17.150561+00:00', TRUE, '[]');
