INSERT INTO products (id, sku, title_it, title_en, category_id, price, stock_quantity, box_quantity, description_it, description_en, image_urls, is_accessory, attributes, created_at, is_active, price_tiers) VALUES ('16ebcef0-1861-4e62-8fc4-1a4050e582bf', 'ST050.0062', 'Omega', NULL, NULL, 0.38, 0, 100, '<p>I flacontubi in plastica Omega sono caratterizzati da un desing arrotondato e differenziante, ideale per prodotti cosmetici viso, corpo, capelli, detergenza e make-up.</p>', '<p> The Omega plastic tottles are characterized by a rounded and differentiating design, ideal for face, body, hair, cleansing and make-up cosmetic products.</p>', '["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/ST050.0062.jpg"]', FALSE, '{"ml": 50, "colore": "Bianco", "finitura": "Nessuna finitura", "categoria": "Flacontubi plastica", "materiale": "PEHDLD", "imboccatura": "Special Fancy piccola"}', '2026-06-16T09:25:59.042047+00:00', TRUE, '[]');
