INSERT INTO products (id, sku, title_it, title_en, category_id, price, stock_quantity, box_quantity, description_it, description_en, image_urls, is_accessory, attributes, created_at, is_active, price_tiers) VALUES ('6c8e2679-94d5-4258-b9fe-c1eff62be323', 'CP410.0067', 'Sophie', NULL, NULL, 0.96, 0, 144, '<p>Il contagocce Sophie, dal design elegante e slanciato, &egrave; ideale per il prelievo di formulazioni fluide come sieri e olii cosmetiche e per la cura dei capelli.</p>', '<p> The Sophie dropper, with an elegant and slender design, is ideal for the withdrawal of fluid formulations such as serums and cosmetic oils and for hair care. </p>', '["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/CP410.0067.jpg"]', TRUE, '{"ml": 0, "colore": "Ghiera bianco, bulbo blu", "finitura": "Nessuna finitura", "categoria": "Contagocce", "materiale": "PP", "imboccatura": "GCMI 24/410"}', '2026-06-16T09:26:07.971875+00:00', TRUE, '[]');
