INSERT INTO legal_pages (id, slug, title_it, title_en, content_it, content_en, updated_at) VALUES ('d11ce0c2-7563-43b1-9647-d0cf47e55de7', 'cookies', 'Cookie Policy', 'Cookie Policy', '<p>Il presente sito utilizza esclusivamente cookie tecnici necessari al corretto funzionamento della sessione di navigazione e all''autenticazione. Non vengono utilizzati cookie di profilazione o di terze parti a fini commerciali.</p>', '<p>This site uses only technical cookies necessary for the proper functioning of the browsing session and authentication. No profiling or third-party cookies are used for commercial purposes.</p>', '2026-06-19T07:29:03.09393+00:00');
INSERT INTO legal_pages (id, slug, title_it, title_en, content_it, content_en, updated_at) VALUES ('5d20e373-2ae1-419e-98f3-ce4a1f11b536', 'terms', 'Condizioni di vendita', 'Terms of sale', '<p>Il sito www.vetronaviglio.it (di seguito, il "Sito") è di proprietà e viene gestito della società Vetronaviglio Srl società unipersonale con sede operativa in Via Don Severino Fracassi 31/39, 20010 Bareggio (MI) – Italy, (di seguito, "Vetronaviglio") e sede legale in Via Don Severino Fracassi 31/39, 20010 Bareggio, P.Iva IT03366120271.</p><p><strong>1.2</strong> Le presenti Condizioni Generali di Utilizzo del Sito (di seguito "Condizioni di Utilizzo"), unitamente alla informativa sulla privacy e alle altre Condizioni Generali pubblicate sul Sito disciplinano l''accesso e l''utilizzo del Sito ad opera dell''Utente, nonché i contratti di vendita "on-line" definiti anche rapporto di fornitura, tra Vetronaviglio e l''Utente.</p><p><strong>1.3</strong> Per contratto di vendita "on line" si intende il contratto a distanza, ossia il negozio giuridico avente per oggetto beni mobili e/o servizi stipulato tra un Fornitore, Vetronaviglio, ed un Cliente, nell''ambito di un sistema di vendita a distanza organizzato da Vetronaviglio che, per tale contratto, impiega esclusivamente la tecnologia di comunicazione a distanza denominata internet.</p><p><strong>1.4</strong> L''utilizzo di specifici servizi offerti sul Sito, da parte di specifiche categorie di utenti (di seguito, "Utenti"), potrebbe comportare l''applicazione, oltre che delle presenti Condizioni di Utilizzo del Sito, anche delle Condizioni Generali di Vendita in vigore per quegli specifici Servizi, per determinate categorie di Utenti.</p><p><strong>1.5</strong> L''accesso al Sito, alle informazioni in esso contenute e/o a qualunque dei Servizi offerti, comporta l''accettazione ed il rispetto delle Condizioni di Utilizzo e di tutte le altre Condizioni Generali di Vendita applicabili. Con il semplice accesso al Sito, le Condizioni di Utilizzo del Sito e tutte le altre Condizioni Generali di Vendita applicabili, si considereranno conosciute ed accettate: per questo motivo, si richiede all''Utente di leggere attentamente il presente documento, stamparlo e conservarlo prima di accedere al Sito.</p><p><strong>1.6</strong> Vetronaviglio si riserva il diritto di modificare e/o aggiornare in tutto o in parte le Condizioni di Utilizzo del Sito e/o le altre Condizioni Generali di Vendita in qualsiasi momento mediante la pubblicazione di nuovi termini o condizioni. L''utilizzo del Sito da parte dell''Utente costituirà accettazione di tutte le Condizioni presenti sul Sito così come modificate e aggiornate. Qualora l''Utente non concordi con uno qualsiasi dei termini o delle Condizioni presenti sul Sito, dovrà interrompere immediatamente l''utilizzo del Sito stesso.</p>', '<p>The website www.vetronaviglio.it (hereinafter, the "Site") is owned and operated by Vetronaviglio Srl società unipersonale with registered office at Via Don Severino Fracassi 31/39, 20010 Bareggio (MI) – Italy, (hereinafter, "Vetronaviglio") and legal seat at Via Don Severino Fracassi 31/39, 20010 Bareggio, VAT IT03366120271.</p><p><strong>1.2</strong> These General Terms of Use of the Site (hereinafter "Terms of Use"), together with the privacy policy and other General Terms published on the Site, govern the access and use of the Site by the User, as well as the "on-line" sales contracts, also defined as supply relationship, between Vetronaviglio and the User.</p><p><strong>1.3</strong> An "on-line" sales contract means a distance contract, i.e. the legal transaction concerning movable goods and/or services entered into between a Supplier, Vetronaviglio, and a Customer, within a distance selling system organized by Vetronaviglio which, for such contract, exclusively employs the distance communication technology known as the internet.</p><p><strong>1.4</strong> The use of specific services offered on the Site by specific categories of users (hereinafter, "Users") may entail the application, in addition to these Terms of Use of the Site, also of the General Terms of Sale in force for those specific Services, for certain categories of Users.</p><p><strong>1.5</strong> Access to the Site, to the information contained therein and/or to any of the Services offered, implies acceptance of and compliance with the Terms of Use and all other applicable General Terms of Sale. By simply accessing the Site, the Terms of Use of the Site and all other applicable General Terms of Sale shall be deemed known and accepted: for this reason, the User is required to read this document carefully, print it and keep it before accessing the Site.</p><p><strong>1.6</strong> Vetronaviglio reserves the right to modify and/or update in whole or in part the Terms of Use of the Site and/or other General Terms of Sale at any time by publishing new terms or conditions. The User''s use of the Site will constitute acceptance of all Terms on the Site as modified and updated. If the User does not agree with any of the terms or conditions on the Site, they must immediately cease using the Site.</p>', '2026-06-19T07:29:03.09393+00:00');
INSERT INTO legal_pages (id, slug, title_it, title_en, content_it, content_en, updated_at) VALUES ('b5ea638a-a1a4-4fef-aefc-e7f216cdde9b', 'privacy', 'Informativa privacy sul trattamento dei dati personali (art. 13 d. lgs. 196/2003)', 'Privacy notice on the processing of personal data (art. 13 Legislative Decree 196/2003)', '<p>Vetronaviglio Srl si impegna a tutelare la privacy dei propri Utenti. La presente informativa descrive la procedura adottata per la tutela dei dati personali quando l''utente visita i siti Web di Vetronaviglio Srl o utilizza un''applicazione on line contenente un collegamento alla presente informativa (collettivamente, "siti"). La presente informativa riguarda anche le informazioni che Vetronaviglio Srl riceve quando viene contattata dall''utente (ad esempio, quando l''utente invia un commento o una richiesta di supporto per un prodotto o un servizio). Il presente documento descrive i dati personali raccolti, le finalità per cui vengono adoperati e le opzioni dell''Utente circa il loro uso da parte di Vetronaviglio Srl. Il presente documento illustra inoltre la procedura adottata da Vetronaviglio Srl per tutelare i dati personali dell''utente e come lo stesso può consultarli e/o modificarli.</p><p>Accedendo ai siti o fornendo i propri dati quando contatta Vetronaviglio Srl, l''utente acconsente alla raccolta di informazioni e alle prassi operative descritte nella presente informativa sulla privacy.</p><p>Ai fini della presente informativa, "dati personali" sono le informazioni che identificano una persona, come ad esempio il nominativo, l''indirizzo postale, l''indirizzo di posta elettronica o il numero di telefono. Nel momento in cui ai dati personali vengono associate altre informazioni, come, ad esempio, le scelte relative alle newsletter inviate tramite posta elettronica, l''acquisto di prodotti o le preferenze circa i prodotti al consumo, tali ulteriori informazioni diventano anch''esse dati personali.</p><h3>Raccolta di informazioni da parte di Vetronaviglio Srl</h3><p>Vetronaviglio Srl riceve i dati direttamente dall''utente. In linea di principio, l''utente può visitare i siti di Vetronaviglio Srl senza immettere dati personali. In alcune pagine, Vetronaviglio Srl può tuttavia chiedere alcuni dati personali dell''utente, allo scopo di fornire un servizio o di eseguire una transazione richiesta dall''utente. L''utente può inoltre fornire alcuni dati personali quando contatta Vetronaviglio Srl (ad esempio, quando invia un commento, un quesito o una richiesta di assistenza). I dati personali raccolti da Vetronaviglio Srl possono includere le seguenti informazioni:</p><ul><li>informazioni di contatto, come il nome, il titolo, il nome della società/organizzazione, l''indirizzo di posta elettronica, i numeri di telefono e di fax e l''indirizzo fisico dell''utente;</li><li>informazioni circa la società e la mansione dell''utente;</li><li>preferenze dell''utente relative al marketing tramite posta elettronica;</li><li>informazioni di carattere finanziario (inclusi i dati relativi a carte di credito o account);</li><li>informazioni come la nazionalità e il paese di residenza dell''utente, che permettono a Vetronaviglio Srl di stabilire se l''utente è idoneo ad essere informato in merito a particolari prassi in base alle disposizioni in materia di controllo sulle esportazioni;</li><li>informazioni utili per personalizzare e facilitare l''uso dei siti da parte dell''utente, compresi i dati tecnici e di accesso;</li><li>richieste circa prodotti e servizi Vetronaviglio Srl, ovvero ordini di prodotti e servizi;</li><li>informazioni che aiutano Vetronaviglio Srl a identificare i prodotti e i servizi più adatti alle esigenze dell''utente;</li><li>dati relativi alla registrazione a Fiere di settore e/o eventi;</li><li>commenti dell''utente circa i siti e i prodotti e servizi Vetronaviglio Srl in generale.</li></ul><p>L''utente non è obbligato a fornire tali dati, ma qualora non li fornisca Vetronaviglio Srl non potrà offrire il servizio richiesto o completare la transazione richiesta dell''utente.</p><h3>Raccolta automatica di informazioni</h3><p>Vetronaviglio Srl raccoglie dati relativi alle visite dell''utente ai propri siti, compresi il tipo di pagine visualizzate, il numero di byte trasferiti, i collegamenti selezionati, i materiali a cui l''utente ha avuto accesso e altre operazioni effettuate sui siti di Vetronaviglio Srl. Vetronaviglio Srl può associare queste informazioni ai dati personali dell''utente e utilizzare le informazioni così combinate conformemente alla presente informativa sulla privacy. Vetronaviglio Srl raccoglie anche alcuni dati standard inviati dal browser dell''utente a tutti i siti Web visitati, come ad esempio l''indirizzo Internet Protocol (IP) dell''utente, il tipo, le funzionalità e la lingua del suo browser, il suo sistema operativo, la data e l''ora dell''accesso al sito e il sito Web da cui l''utente si è collegato a uno dei siti.</p><p>Vetronaviglio Srl non associa questi dati standard ad altri dati personali.</p><h3>Uso delle informazioni da parte di Vetronaviglio Srl</h3><p><strong>Servizi e transazioni.</strong> Vetronaviglio Srl usa i dati personali dell''utente per offrire servizi o eseguire transazioni richieste dall''utente, incluse, senza alcuna limitazione, l''offerta di informazioni su prodotti o servizi Vetronaviglio Srl, la registrazione dei prodotti acquistati, l''elaborazione degli ordini dei prodotti, la gestione dei reclami, la risposta alle richieste di assistenza e la semplificazione dell''utilizzo dei siti Vetronaviglio Srl. I dati raccolti dai siti di Vetronaviglio Srl possono essere associati a informazioni che Vetronaviglio Srl raccoglie o acquisisce con altri mezzi, allo scopo di offrire all''utente un''esperienza più coerente durante le sue interazioni. Tali interazioni includono, senza alcuna limitazione, quelle finalizzate a conoscere l''utente e il modo in cui utilizza prodotti e servizi e interagisce con essi, le interazioni utili allo sviluppo e alla gestione di prodotti e servizi e quelle volte a fornire all''utente informazioni circa prodotti e servizi che potrebbero essere di suo interesse.</p><p><strong>Miglioramento di siti Web e prodotti.</strong> Vetronaviglio Srl può usare i dati personali dell''utente per effettuare analisi commerciali o per altri scopi volti a migliorare la qualità delle attività dei suoi siti e i suoi prodotti o servizi (inclusi i nuovi prodotti o servizi) o a semplificare l''uso degli stessi facendo in modo che l''utente non debba immettere gli stessi dati più volte oppure personalizzando i siti in base alle preferenze o agli interessi specifici dell''utente.</p><p><strong>Comunicazioni.</strong> Vetronaviglio Srl può usare i dati personali dell''utente per aggiornarlo sui prodotti o servizi disponibili a cui l''utente potrebbe essere interessato e per l''invio di sondaggi. L''utente può rifiutare le comunicazioni promozionali contattando Vetronaviglio Srl tramite le informazioni di contatto riportate nella presente informativa sulla privacy. Inoltre, tutte le comunicazioni promozionali tramite posta elettronica inviate da Vetronaviglio Srl contengono un collegamento per la cancellazione dell''iscrizione, che permette all''utente di bloccare l''invio di questo tipo di comunicazioni. Qualora l''utente decida di cancellare la propria iscrizione, Vetronaviglio Srl rimuoverà il suo nominativo dall''elenco in questione entro 10 giorni lavorativi.</p><p><strong>Domande di assunzione.</strong> L''utente può fornire a Vetronaviglio Srl informazioni personali, per esempio mediante un curriculum vitae, in relazione a una candidatura o domanda di assunzione. Vetronaviglio Srl può utilizzare tali informazioni internamente, allo scopo di valutare la richiesta di assunzione. Qualora tale richiesta non venga accolta, Vetronaviglio Srl conserverà le informazioni per usi futuri, per un periodo di tempo limitato, a meno che l''utente chieda esplicitamente a di non conservarle.</p><p>Oltre agli usi elencati in precedenza, Vetronaviglio Srl può utilizzare i dati raccolti al fine di identificare e prevenire frodi, violazioni dei diritti di proprietà intellettuale, dei Termini e condizioni e delle leggi o altri usi impropri dei siti e per reagire ad esse.</p><h3>Uso di cookie e Web beacon</h3><p>I cookie sono file di testo contenenti poche informazioni, che vengono scaricati sul disco rigido dell''utente o nella memoria del suo browser quando l''utente visita un sito di Vetronaviglio Srl. I cookie sono utili per organizzare i contenuti e disegnare il layout dei siti consentendo a Vetronaviglio Srl di riconoscere computer o altri dispositivi che si sono collegati ai suoi siti in passato. I cookie svolgono molte funzioni diverse; ad esempio, permettono ai siti Web di ricordare le preferenze dell''utente e aiutano a migliorare l''usabilità e le prestazioni dei suoi siti e l''esperienza dell''utente durante il loro utilizzo.</p><p>I siti di Vetronaviglio Srl possono anche contenere immagini virtuali, note come beacon o, talvolta, come gif a pixel singolo, che consentono di tenere il conto degli utenti che hanno visitato pagine specifiche. Vetronaviglio Srl può includere Web beacon nelle newsletter o nei messaggi promozionali di posta elettronica per stabilire se l''utente ha aperto i messaggi e interagito con essi.</p><h3>Categorie di cookie</h3><p><strong>Cookie strettamente necessari.</strong> Questi cookie sono indispensabili perché permettono all''utente di navigare nei siti di Vetronaviglio Srl e di utilizzarne la funzionalità, specie in relazione alla ricerca di informazioni e all''effettuazione di ordini. Senza questi cookie, i servizi richiesti dall''utente non potranno essere forniti. Questi cookie non raccolgono informazioni dell''utente che potrebbero essere utilizzate a fini di marketing o per ricordare i siti Internet visitati dall''utente.</p><p><strong>Cookie prestazionali.</strong> Questi cookie raccolgono informazioni sul modo in cui l''utente usa i siti di Vetronaviglio Srl, per esempio sulle pagine visitate più spesso e su eventuali messaggi di errori ricevuti in alcune pagine. Questi cookie raccolgono soltanto dati anonimi che vengono utilizzati per migliorare il funzionamento dei siti di Vetronaviglio Srl e non vengono adoperati per inviare all''utente pubblicità on line.</p><p><strong>Cookie relativi alle funzionalità e al profilo.</strong> Questi cookie permettono ai siti di Vetronaviglio Srl di memorizzare le informazioni fornite dall''utente, come ad esempio le preferenze relative alla lingua, e di salvare dati tecnici utili ai fini dell''interazione dell''utente con tali siti.</p><p><strong>Cookie pubblicitari.</strong> Questi cookie possono essere usati per l''invio degli annunci pubblicitari di maggiore interesse per l''utente. Possono anche essere usati per limitare il numero di visualizzazioni di un annuncio pubblicitario e per contribuire a determinare l''efficacia di una campagna pubblicitaria.</p><h3>Divulgazione dei dati personali dell''utente</h3><p>Fatto salvo quanto illustrato in precedenza, i dati personali dell''utente, raccolti da Vetronaviglio Srl tramite i propri siti o forniti dall''utente quando contatta Vetronaviglio Srl, non verranno condivisi al di fuori di Vetronaviglio Srl senza l''autorizzazione dell''utente.</p><p><strong>Divulgazione dei dati ai fornitori di servizi.</strong> Vetronaviglio Srl stipula contratti con altre società allo scopo di fornire servizi per proprio conto. Vetronaviglio Srl fornisce a queste società solo i dati personali dell''utente di cui esse necessitano per offrire tali servizi in modo efficace.</p><p><strong>Divulgazione ai distributori.</strong> Per rispondere a richieste dell''utente, Vetronaviglio Srl potrebbe condividere i dati personali dell''utente con Società che distribuiscono i prodotti Vetronaviglio Srl.</p><p><strong>Divulgazione correlata alle transazioni.</strong> In correlazione con alcune transazioni, Vetronaviglio Srl può divulgare alcuni o tutti i dati personali dell''utente a istituti finanziari, autorità giudiziarie e Società di spedizione o servizi postali interessati all''esecuzione della transazione.</p><h3>Sicurezza</h3><p>Vetronaviglio Srl si impegna a tutelare la sicurezza dei dati personali dell''utente. A tal fine ricorre a varie tecnologie e procedure per la sicurezza che contribuiscono a proteggere i dati personali dell''utente dalla loro divulgazione o da accessi e usi non autorizzati.</p><h3>Consultazione dei dati personali dell''utente</h3><p>L''utente può sempre chiedere di consultare e modificare i propri dati personali, raccolti tramite i siti di Vetronaviglio Srl o forniti quando contatta Vetronaviglio Srl, oppure può chiedere a Vetronaviglio Srl di non usare più tali dati contattando Vetronaviglio Srl tramite le informazioni di contatto riportate di seguito.</p><h3>Contatti</h3><p>Email: info@vetronaviglio.it</p><p>Indirizzo postale:<br>Vetronaviglio Srl<br>Via Don Severino Fracassi 31/39<br>20010 Bareggio (MI) - Italia</p><p><strong>Ultimo aggiornamento:</strong> Bareggio 24/05/2018.</p>', '<p>Vetronaviglio Srl is committed to protecting the privacy of its Users. This notice describes the procedure adopted for the protection of personal data when the user visits the websites of Vetronaviglio Srl or uses an online application containing a link to this notice (collectively, the "sites"). This notice also covers information that Vetronaviglio Srl receives when contacted by the user (for example, when the user submits a comment or a support request for a product or service). This document describes the personal data collected, the purposes for which they are used and the User''s options regarding their use by Vetronaviglio Srl. This document also illustrates the procedure adopted by Vetronaviglio Srl to protect the user''s personal data and how the user can view and/or modify them.</p><p>By accessing the sites or providing their data when contacting Vetronaviglio Srl, the user consents to the collection of information and to the operating practices described in this privacy notice.</p><p>For the purposes of this notice, "personal data" means information that identifies a person, such as name, postal address, email address or telephone number. When other information is associated with personal data, such as newsletter preferences, product purchases or consumer product preferences, such additional information also becomes personal data.</p><h3>Collection of information by Vetronaviglio Srl</h3><p>Vetronaviglio Srl receives data directly from the user. In principle, the user may visit Vetronaviglio Srl''s sites without entering personal data. On some pages, however, Vetronaviglio Srl may ask for some personal data from the user in order to provide a service or perform a transaction requested by the user. The user may also provide personal data when contacting Vetronaviglio Srl (for example, when submitting a comment, a question or a support request). Personal data collected by Vetronaviglio Srl may include the following information:</p><ul><li>contact information such as name, title, company/organization name, email address, telephone and fax numbers, and physical address;</li><li>information about the user''s company and job role;</li><li>user preferences regarding email marketing;</li><li>financial information (including credit card or account data);</li><li>information such as nationality and country of residence, which allows Vetronaviglio Srl to determine whether the user is eligible to be informed about particular practices under export control provisions;</li><li>information useful for personalizing and facilitating the user''s use of the sites, including technical and access data;</li><li>requests about Vetronaviglio Srl products and services, or orders for products and services;</li><li>information that helps Vetronaviglio Srl identify the products and services best suited to the user''s needs;</li><li>data relating to registration for trade fairs and/or events;</li><li>user comments about the sites and Vetronaviglio Srl products and services in general.</li></ul><p>The user is not obliged to provide such data, but if they do not, Vetronaviglio Srl will not be able to provide the requested service or complete the transaction requested by the user.</p><h3>Automatic collection of information</h3><p>Vetronaviglio Srl collects data relating to the user''s visits to its sites, including the type of pages viewed, the number of bytes transferred, the links selected, the materials accessed by the user and other operations carried out on Vetronaviglio Srl''s sites. Vetronaviglio Srl may associate this information with the user''s personal data and use the combined information in accordance with this privacy notice. Vetronaviglio Srl also collects certain standard data sent by the user''s browser to all websites visited, such as the user''s Internet Protocol (IP) address, browser type, features and language, operating system, date and time of access to the site and the website from which the user connected to one of the sites.</p><p>Vetronaviglio Srl does not associate this standard data with other personal data.</p><h3>Use of information by Vetronaviglio Srl</h3><p><strong>Services and transactions.</strong> Vetronaviglio Srl uses the user''s personal data to provide services or perform transactions requested by the user, including, without limitation, providing information about Vetronaviglio Srl products or services, registering purchased products, processing product orders, managing complaints, responding to support requests and simplifying the use of Vetronaviglio Srl sites. Data collected from Vetronaviglio Srl sites may be associated with information that Vetronaviglio Srl collects or acquires by other means, in order to provide the user with a more consistent experience during their interactions.</p><p><strong>Improvement of websites and products.</strong> Vetronaviglio Srl may use the user''s personal data to carry out business analyses or for other purposes aimed at improving the quality of its sites and its products or services (including new products or services) or to simplify their use by ensuring that the user does not have to enter the same data multiple times or by customizing the sites according to the user''s specific preferences or interests.</p><p><strong>Communications.</strong> Vetronaviglio Srl may use the user''s personal data to update them on available products or services that may be of interest and to send surveys. The user may refuse promotional communications by contacting Vetronaviglio Srl using the contact information provided in this privacy notice.</p><p><strong>Job applications.</strong> The user may provide Vetronaviglio Srl with personal information, for example by means of a curriculum vitae, in connection with a job application. Vetronaviglio Srl may use such information internally for the purpose of evaluating the application.</p><h3>Use of cookies and web beacons</h3><p>Cookies are small text files that are downloaded to the user''s hard drive or browser memory when the user visits a Vetronaviglio Srl site. Cookies help organize content and design the layout of sites by allowing Vetronaviglio Srl to recognize computers or other devices that have connected to its sites in the past.</p><h3>Categories of cookies</h3><p><strong>Strictly necessary cookies.</strong> These cookies are essential as they allow the user to navigate Vetronaviglio Srl sites and use their functionality, particularly in relation to searching for information and placing orders.</p><p><strong>Performance cookies.</strong> These cookies collect information about how the user uses Vetronaviglio Srl sites, for example which pages are visited most often and whether error messages are received on certain pages.</p><p><strong>Functionality and profile cookies.</strong> These cookies allow Vetronaviglio Srl sites to remember information provided by the user, such as language preferences, and to save technical data useful for the user''s interaction with such sites.</p><p><strong>Advertising cookies.</strong> These cookies may be used to deliver advertisements of greater interest to the user. They may also be used to limit the number of times an advertisement is viewed and to help measure the effectiveness of an advertising campaign.</p><h3>Disclosure of the user''s personal data</h3><p>Subject to the foregoing, the user''s personal data collected by Vetronaviglio Srl through its sites or provided by the user when contacting Vetronaviglio Srl will not be shared outside Vetronaviglio Srl without the user''s authorization.</p><p><strong>Disclosure to service providers.</strong> Vetronaviglio Srl contracts with other companies to provide services on its behalf. Vetronaviglio Srl provides these companies only with the user''s personal data that they need to provide such services effectively.</p><p><strong>Disclosure to distributors.</strong> To respond to user requests, Vetronaviglio Srl may share the user''s personal data with companies that distribute Vetronaviglio Srl products.</p><p><strong>Transaction-related disclosure.</strong> In connection with certain transactions, Vetronaviglio Srl may disclose some or all of the user''s personal data to financial institutions, judicial authorities and shipping or postal services involved in the execution of the transaction.</p><h3>Security</h3><p>Vetronaviglio Srl is committed to protecting the security of the user''s personal data. To this end, it uses various security technologies and procedures that help protect the user''s personal data from unauthorized disclosure, access or use.</p><h3>Access to the user''s personal data</h3><p>The user may always request to view and modify their personal data collected through Vetronaviglio Srl sites or provided when contacting Vetronaviglio Srl, or may ask Vetronaviglio Srl to stop using such data by contacting Vetronaviglio Srl using the contact information below.</p><h3>Contacts</h3><p>Email: info@vetronaviglio.it</p><p>Postal address:<br>Vetronaviglio Srl<br>Via Don Severino Fracassi 31/39<br>20010 Bareggio (MI) - Italy</p><p><strong>Last updated:</strong> Bareggio, 24/05/2018.</p>', '2026-06-19T07:29:03.09393+00:00');
