": 0}', '{"id": "712b2f9d-ffe4-4a20-b854-b4ad974a8170", "sku": "CL0S0.0026", "price": 1.2, "title_en": null, "title_it": "Fancy Piccola", "is_active": true, "attributes": {"ml": 0, "colore": "Interno argento brillante, Esterno trasparente lucido", "finitura": "Nessuna finitura", "categoria": "Capsule - Disctop", "materiale": "k resin + PP", "imboccatura": "Special Fancy piccola"}, "created_at": "2026-06-16T09:25:17.530481+00:00", "image_urls": ["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/CL0S0.0026.jpg"], "category_id": null, "box_quantity": 112, "is_accessory": false, "description_en": "<p>The cap Fancy Piccola,&nbsp;with its classical and feminine&nbsp;design, is made of two parts and it&nbsp;is&nbsp;perfect for&nbsp;skincare, and personal care products.&nbsp;It is matchable with the tottle <a href=\"https://www.vetronaviglio.it/en/plastic-low-moq/lowmoqsubcategories/33/fancy-plastic-tottles-low-moq-selection\">Fancy</a> and <a href=\"https://www.vetronaviglio.it/en/plastic-low-moq/lowmoqsubcategories/35/omega-plastic-tottles-low-moq-selection\">Omega</a>.</p>  <p>PEG&nbsp;diameter&nbsp;1.4 mm</p>  <p>LINER INCLUDED</p>", "description_it": "<p>La capsula Fancy Piccola, &egrave; composta da due componenti che la impreziosiscono ed&nbsp;&egrave; perfetta per&nbsp;prodotti cosmetici, per capelli e detergenza.&nbsp;E&#39; compatibile con i flacontubi <a href=\"https://www.vetronaviglio.it/it/packaging-plastica-low-moq/lowmoqsubcategories/33/fancy-flacontubi-plastica-low-moq-selection\">Fancy</a> e <a href=\"https://www.vetronaviglio.it/it/packaging-plastica-low-moq/lowmoqsubcategories/35/omega-flacontubi-plastica-low-moq-selection\">Omega</a>.</p>  <p>PIOLO diametro 1.4 mm</p>  <p>GUARNIZIONE INCLUSA</p>", "stock_quantity": 703}', '2026-06-18T07:15:13.516725+00:00');
