ory": false, "description_en": "<p>The York dspenser pump, thanks to its special &quot;pump up&quot; mechanism, represents the perfect solution for cleaner waters and nail care products. The double spring provide&nbsp;a confortable use and the flip top cover guarantee an hygienic conservation of the product.</p>  <p>Dosage: 500 mcl.</p>", "description_it": "<p>Il dispenser York, grazie al suo speciale meccanismo &quot;pump up&quot;, rappresenta la perfetta soluzione per l&#39;erogazione di prodotti struccanti e&nbsp;nail care. Le&nbsp;due&nbsp;molle assicurano&nbsp;un&#39;erogazione uniforme ed il cover flip top garantisce una conservazione igienica del prodotto.</p>  <p>Dosaggio pompa: 500 mcl.</p>", "stock_quantity": 17730}', '2026-06-18T07:15:13.516725+00:00');
INSERT INTO audit_logs (id, user_id, table_name, record_id, action, old_data, new_data, created_at) VALUES ('ddaa0699-e1e4-4854-b021-1705f8e9c5bd', NULL, 'products', 'd90d09f5-89e8-47c2-978c-a28319579140', 'UPDATE', '{"id": "d90d09f5-89e8-47c2-978c-a28319579140", "sku": "DR410.0036/1", "price": 1.7, "title_en": null, "title_it": "New Cristal", "is_active": true, "attributes": {"ml": 0, "colore": "Oro Rosa Brillante", "finitura": "Metallizato", "categoria": "Dispenser", "materiale": "PP", "imboccatura": "GCMI 24/410"}, "created_at": "2026-06-16T09:25:52.237717+00:00", "image_urls": ["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/DR410.0036/1.jpg"], "category_id": null, "box_quantity": 500, "is_accessory": false, "description_en": "<pre data-placeholder=\"Traduzione\" dir=\"ltr\" id=\"tw-target-text\"> The New Cristal dispenser has been specially designed to be coordinated with the New Cristal bottle, adapting the lines and the design of the bottle itself, in order to give it the maximum aesthetic balance. Ideal for dispensing a wide range of cosmetic products, for cleansing and hair care.</pre>", "description_it": "<p>Il dispenser New Cristal &egrave; stato appositamente progettato per essere coordinato al flacone New Cristal, adattandolo le linee e il desing del flacone stesso, al fine di conferirgli il massimo equilibrio estetico. Ideale per l&rsquo;erogazione di un&rsquo;ampia gamma di prodotti cosmetici, per la detergenza e per la cura dei capelli.</p>", "stock_quantity": 2506}', '{"id": "d90d09f5-89e8-47c2-978c-a28319579140", "sku": "DR410.0036/1", "price": 1.7, "title_en": null, "title_it": "New Cristal", "is_active": true, "attributes": {"ml": 0, "colore": "Oro Rosa Brillante", "finitura": "Metallizato", "categoria": "Dispenser", "materiale": "PP", "imboccatura": "GCMI 24/410"}, "created_at": "2026-06-16T09:25:52.237717+00:00", "image_urls": ["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceB