INSERT INTO audit_logs (id, user_id, table_name, record_id, action, old_data, new_data, created_at) VALUES ('10192d68-cd7e-4653-883a-423a920cba6c', NULL, 'products', 'dfa4b370-13ee-423f-975f-c5761520dff7', 'UPDATE', '{"id": "dfa4b370-13ee-423f-975f-c5761520dff7", "sku": "DG410.0001", "price": 0.16, "title_en": null, "title_it": "Spray Griffe", "is_active": true, "attributes": {"ml": 0, "colore": "Bianco", "finitura": "Nessuna finitura", "categoria": "Dispenser", "materiale": "PP", "imboccatura": "Spray New Griffe"}, "created_at": "2026-06-16T09:26:12.836168+00:00", "image_urls": ["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/DG410.0001.jpg"], "category_id": null, "price_tiers": [], "box_quantity": 0, "is_accessory": false, "description_en": "<p>The overcap for spray Griffe has been designed to protect the actuator of the&nbsp;spray pump Griffe; its shape and proportions have been specifically designed for the best aesthetic result. It&#39;s ideal for dispensing of a variety of skincare, personal care and haircare products.</p>", "description_it": "<p>Il cover spray Griffe &egrave; stato progettato per essere abbinato allo&nbsp;spray Griffe proteggendo il tasto, seguendo&nbsp;linee e proporzioni, per conferire il massimo equilibrio estetico. Ideale per l&rsquo;erogazione di un&rsquo;ampia gamma di prodotti cosmetici, per la detergenza e per la cura dei capelli.</p>", "stock_quantity": 0}', '{"id": "dfa4b370-13ee-423f-975f-c5761520dff7", "sku": "DG410.0001", "price": 0.16, "title_en": null, "title_it": "Spray Griffe", "is_active": true, "attributes": {"ml": 0, "colore": "Bianco", "finitura": "Nessuna finitura", "categoria": "Dispenser", "materiale": "PP", "imboccatura": "Spray New Griffe"}, "created_at": "2026-06-16T09:26:12.836168+00:00", "image_urls": ["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/DG410.0001.jpg"], "category_id": null, "price_tiers": [], "box_quantity": 0, "is_accessory": true, "description_en": "<p>The overcap for spray Griffe has been designed to protect the actuator of the&nbsp;spray pump Griffe; its shape and proportions have been specifically designed for the best aesthetic result. It&#39;s ideal for dispensing of a variety of skincare, personal care and haircare products.</p>", "description_it": "<p>Il cover spray Griffe &egrave; stato progettato per essere abbinato allo&nbsp;spray Griffe proteggendo il tasto, seguendo&nbsp;linee e proporzioni, per conferire il massimo equilibrio estetico. Ideale per l&rsquo;erogazione di un&rsquo;ampia gamma di prodotti cosmetici, per la detergenza e per la cura dei capelli.</p>", "stock_quantity": 0}', '2026-06-18T10:58:48.157221+00:00');
