INSERT INTO audit_logs (id, user_id, table_name, record_id, action, old_data, new_data, created_at) VALUES ('ed29110f-713d-405d-aa18-458f1712a99e', NULL, 'products', '8325489d-318a-4c54-a4bd-9781014a1cf2', 'UPDATE', '{"id": "8325489d-318a-4c54-a4bd-9781014a1cf2", "sku": "CZ410.0027", "price": 0.78, "title_en": null, "title_it": "Twist-Off Sirio", "is_active": true, "attributes": {"ml": 0, "colore": "Bianco Opaco", "finitura": "Nessuna finitura", "categoria": "Capsule - Disctop", "materiale": "PP", "imboccatura": "TWIST-OFF"}, "created_at": "2026-06-16T09:26:14.136443+00:00", "image_urls": ["https://vsqzxudijllpocrbqfbo.supabase.co/storage/v1/object/public/ecommerceBUK/products/CZ410.0027.jpg"], "category_id": null, "price_tiers": [], "box_quantity": 1500, "is_accessory": false, "description_en": "<p>The cap Sirio is characterized by the twist-off closure system that&nbsp;makes&nbsp;the dispensing extremely practical and easy to use. Just rotate the cap of half of a turn to make the lotion&nbsp;come out from the bottle. Then turn back the cap to close it again.</p>  <p><strong>FIT ONLY WITH PLASTIC BOTTLES AMBRA 125 ML AND 250 ML WITH SAME NECK FINISH.</strong></p>  <p>LINER INCLUDED</p>", "description_it": "<p>La capsula Sirio &egrave; caratterizzata dalla chiusura&nbsp;twist-off che rende&nbsp;l&#39;erogazione estremamente pratica e funzionale. Basta ruotare la capsula di mezzo giro e il fluido potr&agrave; fuoriuscire dal flacone attraverso il foro. Ruotarla nel senso inverso per chiudere nuovamente la capsula.</p>  <p><strong>COMPATIBILE SOLO CON FLACONI IN PLASTICA&nbsp;AMBRA 125 ML E AMBRA 250 ML CON LA STESSA BOCCA</strong></p>  <p>GUARNIZIONE INCLUSA</p>", "stock_quantity": 5740}', '{"id": "8325489d-318a-4c54-a4bd-9781014a1cf2", "sku": "CZ410.0027", "price": 0.78, "title_en": null, "title_it": "Twist-Off Sirio", "is_active": true, "attributes": {"ml": 0, "colore": "Bianco Opaco", "finitura": "Nessuna finitura", "categoria": "Capsule - Disctop", "materiale": "